const text = $input.first().json.text;

const fallbackCity = "Madrid,ES";

function parseCity(str) {
    const firstBrace = str.indexOf('{');
    const lastBrace = str.lastIndexOf('}');

    if (firstBrace !== -1 && lastBrace !== -1) {
        const jsonString = str.substring(firstBrace, lastBrace + 1);
        try {
            const data = JSON.parse(jsonString);

            return data.ciudad || fallbackCity;
        } catch (e) {
            console.log("Error al parsear JSON del clima");
        }
    }
    return fallbackCity;
}

const ciudadDetectada = parseCity(text);

return {
    json: {
        ciudad: ciudadDetectada
    }
};

