const eventos = $input.all();
const nombreNodoIA = 'Datos modificar evento'; 

// NUEVA FUNCIÓN: Mantiene la hora tal cual la vemos en España
function aFechaLocalISO(fechaObj) {
    const tzo = -fechaObj.getTimezoneOffset();
    const dif = tzo >= 0 ? '+' : '-';
    const pad = (num) => (num < 10 ? '0' : '') + num;

    return fechaObj.getFullYear() +
        '-' + pad(fechaObj.getMonth() + 1) +
        '-' + pad(fechaObj.getDate()) +
        'T' + pad(fechaObj.getHours()) +
        ':' + pad(fechaObj.getMinutes()) +
        ':' + pad(fechaObj.getSeconds());
}

let datosNuevos = {};
try {
    datosNuevos = $(nombreNodoIA).first().json;
} catch (e) {
    return { json: { accion: "error", error_tipo: "NODO_ANTERIOR_NO_ENCONTRADO" } };
}

// CASO 1: NO HAY EVENTOS
if (eventos.length === 0 || !eventos[0].json.id) {
    return { json: { accion: "nada", q_buscada: datosNuevos.q || 'event' } };
}

// CASO 2: VARIOS EVENTOS (Solo ID)
if (eventos.length > 1) {
    const botones = eventos.slice(0, 5).map(evento => {
        const fecha = new Date(evento.json.start.dateTime || evento.json.start.date);
        const fechaTxt = fecha.toLocaleString('es-ES', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });
        return [{
            text: `${evento.json.summary} (${fechaTxt})`,
            callback_data: `mod|${evento.json.id}` // Solo mandamos el ID
        }];
    });
    return { json: { accion: "preguntar", reply_markup: { inline_keyboard: botones } } };
}

// CASO 3: UN SOLO EVENTO
const original = eventos[0].json;
const datosIA = $('Datos modificar evento').first().json;

// 1. Modificar Título y Descripción si la IA detectó cambios
if (datosIA.newSummary) original.summary = datosIA.newSummary;
if (datosIA.newDescription) original.description = datosIA.newDescription;

// 2. Gestión inteligente de fecha y duración
let fechaBaseOriginal = (original.start.dateTime || original.start.date).split('T')[0];
let finalStart = original.start.dateTime || original.start.date;
let finalEnd = original.end.dateTime || original.end.date;

if (datosIA.newStart) {
    // Si la IA manda solo hora (empieza por T), mantenemos el día original
    if (datosIA.newStart.startsWith('T')) {
        finalStart = fechaBaseOriginal + datosIA.newStart;
    } else {
        finalStart = datosIA.newStart;
    }

    // Calculamos duración original para mantener el bloque de tiempo
    const msInicioOriginal = new Date(original.start.dateTime || original.start.date).getTime();
    const msFinOriginal = new Date(original.end.dateTime || original.end.date).getTime();
    const duracionOriginalMs = msFinOriginal - msInicioOriginal;

    const nuevoInicioMs = new Date(finalStart).getTime();
    const nuevoFinDate = new Date(nuevoInicioMs + duracionOriginalMs);

    const pad = (n) => n.toString().padStart(2, '0');
    finalEnd = `${nuevoFinDate.getFullYear()}-${pad(nuevoFinDate.getMonth() + 1)}-${pad(nuevoFinDate.getDate())}T${pad(nuevoFinDate.getHours())}:${pad(nuevoFinDate.getMinutes())}:${pad(nuevoFinDate.getSeconds())}`;
}

// 3. Gestión de Recordatorios
let finalReminder = 15;
if (original.reminders?.overrides?.length > 0) {
    finalReminder = original.reminders.overrides[0].minutes;
}
if (datosIA.newReminder) finalReminder = datosIA.newReminder;

return {
    json: {
        accion: "modificar",
        id: original.id,
        updateSummary: original.summary,
        updateDescription: original.description || "",
        updateStart: finalStart,
        updateEnd: finalEnd,
        updateReminder: finalReminder
    }
};

const text = $input.first().json.text;
const firstBrace = text.indexOf('{');
const lastBrace = text.lastIndexOf('}');

if (firstBrace !== -1 && lastBrace !== -1) {
    const jsonString = text.substring(firstBrace, lastBrace + 1);
    try {
        const data = JSON.parse(jsonString);

        let finalStart = data.start;
        let finalEnd = data.end;

        if (data.allday === true) {
            finalStart = data.start.split('T')[0];

            const startDateObj = new Date(finalStart);
            const nextDay = new Date(startDateObj);
            nextDay.setDate(startDateObj.getDate() + 1);
            finalEnd = nextDay.toISOString().split('T')[0];
        }

        return {
            json: {
                summary: data.summary,
                description: data.description,
                start: finalStart,
                end: finalEnd,
                allday: data.allday || false, 
                reminder: data.reminder !== undefined ? data.reminder : null
            }
        };
    } catch (e) { return { json: { error: "Error JSON" } }; }
}
return { json: {} };

